import { jsx, jsxs } from 'react/jsx-runtime';
import { classNames } from '../../../helpers/classnames.js';

const AnimatedProgress = ({ className, ...props }) => {
    // начальные значения анимации, будут изменяться для каждой следующей пары "персиков" для создания эффекта размытого следа
    const pairStyleSettings = {
        animationDelay: 0,
        opacity: 1,
        zIndex: 20,
    };
    // шаг с которым будут изменяться стили каждого следующего шага
    const stepChanges = {
        animationDelay: 5,
        opacity: 1.18,
        zIndex: 1,
    };
    // количество пар "персиков" создающее визуальный эффект размытого следа
    const pairsAmount = 20;
    // данные стилей для каждой пары
    const pairsData = [];
    for (let pairs = 0; pairs <= pairsAmount; pairs++) {
        // наполняем массив, клонируя объект настроек
        pairsData.push({ ...pairStyleSettings });
        // изменяем текущие настройки на один шаг
        pairStyleSettings.animationDelay += stepChanges.animationDelay;
        pairStyleSettings.opacity /= stepChanges.opacity;
        // pairStyleSettings.zIndex -= stepChanges.zIndex;
    }
    return (jsx("span", { "data-testid": "AnimatedProgress", className: classNames('dsb-progress-animated', className), ...props, role: "progressbar", children: pairsData.map((data, i) => (jsxs("div", { className: "dsb-progress-animated__pair", style: {
                animationDelay: data.animationDelay + 'ms',
                opacity: data.opacity,
                zIndex: data.zIndex,
            }, children: [jsx("span", { className: "dsb-progress-animated__circle" }), jsx("span", { className: "dsb-progress-animated__circle" })] }, i))) }));
};

export { AnimatedProgress };
